        // mapLocation: { row: 5, col: 5 },
        playerPosition: { row: 2, col: 3 },
        message: '',
                isLandscape: window.innerWidth > window.innerHeight,
            registerMenu: false,
            mobile: false,
            mobileHor: true,
            whereAmI: 'geaga',
            isOn: false,
            statsVisible: false,
            showEascaLocation: true,
            isVisible: false,
            // whereAmI: localStorage.getItem('whereAmI')
            data: "",
            speakWithDM: true,
            isEncounterComponentVisible: true,
            encounterID: 0,
            orientation: window.matchMedia('(orientation:portrait)').matches ? 'portrait' : 'landscape'
        }

    }

    handleTileTouch = (row, col) => {
      if (this.canMove(row, col)) { // Add your own logic to check if the move is allowed
        this.setState({
          playerPosition: { row, col },
        });

        if (this.isAtMapLocation(row, col)) {
          alert('Hey! You reached the location!');
        }
      }
    };

  canMove = (row, col) => {
    const { mapData } = this.props;
    return mapData[row][col] === 1;
    };

    isAtMapLocation = (row, col) => {
      const { mapLocation } = this.state;
      return row === mapLocation.row && col === mapLocation.col;
    };

    renderGameBoard() {
      const { mapData } = this.props;
      const { playerPosition } = this.state;

      return mapData.map((row, rowIndex) => (
        <div key={`row-${rowIndex}`} className="game-row">
          {row.map((tile, colIndex) => (
            <div
              key={`tile-${rowIndex}-${colIndex}`}
              className={`game-tile ${tile === 1 ? 'non-walkable' : ''} ${
                rowIndex === playerPosition.row && colIndex === playerPosition.col
                  ? 'player-icon'
                  : ''
              }`}
              onTouchStart={() => this.handleTileTouch(rowIndex, colIndex)}
            >
              {/* {tile === 0 && <div className="obstacle"></div>} */}
            </div>
          ))}
        </div>
      ));
    }
  handleResize = () => {
    this.setState({
      isLandscape: window.innerWidth > window.innerHeight,
    });
    this.updateMessage();
  };
  updateMessage = () => {
    const newMessage = this.state.isLandscape
      ? 'Hello Landscape'
      : 'Hello Portrait';
    this.setState({
      message: newMessage,
    });
  };

  componentDidMount() { 

    window.addEventListener('resize', this.handleResize);
    this.updateMessage();


  }
    componentWillUnmount() {
window.removeEventListener('resize', this.handleResize);
    }
    render() {
      const { message } = this.state;
      return (

        <div className='world-map-container'>


        {message}
        <div className="world-map">{this.renderGameBoard()}</div>
      </div>)
    }
}
